import React, { useEffect, useRef, useState } from 'react';
import { useDashboard } from '../../context/DashboardContext';
import { useCommand } from '../../hooks/useCommand';
import StatusIndicator from '../StatusIndicator/StatusIndicator';
import SelectControl from '../Controls/SelectControl';
import ToggleControl from '../Controls/ToggleControl';
import ButtonControl from '../Controls/ButtonControl';
import DynamicInputControl from '../Controls/DynamicInputControl';
import InfoDisplayControl from '../Controls/InfoDisplayControl';
import './FeatureCard.css';

function FeatureCard({ feature, moduleStatus }) {
  const { featureStatus, setFeatureStatus, toggleState, setToggleState } = useDashboard();
  const { sendCommand } = useCommand();
  const [selectValues, setSelectValues] = useState({});
  const [dynamicValues, setDynamicValues] = useState({});
  const [isExpanded, setIsExpanded] = useState(false);
  const cardRef = useRef(null);

  const status = featureStatus[feature.id];
  const isOffline = moduleStatus === 'offline';
  const hasDynamicControl = feature.controls?.some(control => control.type === 'dynamic');

  const getSelectedTarget = () => {
    const selectControl = feature.controls.find(control => control.type === 'select');
    if (selectControl && selectValues[selectControl.id]) {
      return selectValues[selectControl.id];
    }
    return selectControl ? selectControl.options[0] : null;
  };

  const handleButtonClick = async action => {
    if (action.includes('_copy_')) {
      const infoControl = feature.controls.find(control => control.type === 'info');
      if (infoControl) {
        const fieldType = action.includes('_copy_ip') ? 'ip' : 'mac';
        const field = infoControl.fields.find(item => item.id === fieldType);
        if (field) {
          try {
            await navigator.clipboard.writeText(field.value);
            alert(`${field.label} copied to clipboard!`);
          } catch (err) {
            console.error('Failed to copy:', err);
          }
        }
      }
      return;
    }

    const dynamicControl = feature.controls.find(control => control.type === 'dynamic');
    if (dynamicControl) {
      const target = getSelectedTarget();
      const fields = dynamicControl.fields[target] || [];

      if (fields.length > 0) {
        const currentDynamicValues = dynamicValues[dynamicControl.id] || {};
        for (const field of fields) {
          const fieldValue = currentDynamicValues[field.id];

          if (!fieldValue && fieldValue !== 0) {
            alert(`Please enter ${field.label}`);
            return;
          }

          const numValue = parseFloat(fieldValue);
          if (Number.isNaN(numValue)) {
            alert(`${field.label} must be a valid number`);
            return;
          }

          if (numValue < field.min || numValue > field.max) {
            alert(`${field.label} must be between ${field.min} and ${field.max}`);
            return;
          }
        }
      }
    }

    const params = { ...selectValues, ...dynamicValues };
    setFeatureStatus(feature.id, 'running');
    const res = await sendCommand(action, params);
    setFeatureStatus(feature.id, res.ok ? 'pass' : 'fail');
  };

  const handleToggle = async (controlId, actionOn, actionOff) => {
    const currentState = toggleState[controlId] || false;
    const newState = !currentState;
    const action = newState ? actionOn : actionOff;

    setFeatureStatus(feature.id, 'running');
    const res = await sendCommand(action);

    if (res.ok) {
      setToggleState(controlId, newState);
      setFeatureStatus(feature.id, 'pass');
    } else {
      setFeatureStatus(feature.id, 'fail');
    }
  };

  const handleSelectChange = (controlId, value) => {
    setSelectValues(prev => ({ ...prev, [controlId]: value }));
    if (hasDynamicControl) {
      setIsExpanded(true);
    }
  };

  const handleDynamicChange = (controlId, values) => {
    setDynamicValues(prev => ({ ...prev, [controlId]: values }));
    if (hasDynamicControl) {
      setIsExpanded(true);
    }
  };

  const handleCardClick = () => {
    if (hasDynamicControl) {
      setIsExpanded(true);
    }
  };

  useEffect(() => {
    if (!hasDynamicControl) return undefined;

    const handleOutsideClick = event => {
      if (cardRef.current && !cardRef.current.contains(event.target)) {
        setIsExpanded(false);
      }
    };

    document.addEventListener('mousedown', handleOutsideClick);
    document.addEventListener('touchstart', handleOutsideClick);

    return () => {
      document.removeEventListener('mousedown', handleOutsideClick);
      document.removeEventListener('touchstart', handleOutsideClick);
    };
  }, [hasDynamicControl]);

  const selectedTarget = getSelectedTarget();
  const cardClassName = `feature-card ${hasDynamicControl ? 'expandable-card' : ''} ${hasDynamicControl && isExpanded ? 'expanded' : ''}`.trim();

  return (
    <div ref={cardRef} className={cardClassName} onClick={handleCardClick}>
      <div className="feature-title">{feature.title}</div>
      <div className="feature-desc">{feature.desc}</div>
      <StatusIndicator status={status} />

      {feature.controls.map((control, index) => {
        switch (control.type) {
          case 'select':
            return (
              <SelectControl
                key={control.id}
                control={control}
                value={selectValues[control.id] || control.options[0]}
                onChange={handleSelectChange}
              />
            );

          case 'dynamic':
            return (
              <DynamicInputControl
                key={control.id}
                control={control}
                target={selectedTarget}
                value={dynamicValues[control.id] || {}}
                onChange={handleDynamicChange}
              />
            );

          case 'info':
            return <InfoDisplayControl key={control.id} control={control} />;

          case 'toggle':
            return (
              <ToggleControl
                key={control.id}
                control={control}
                isOn={toggleState[control.id] || false}
                onToggle={handleToggle}
              />
            );

          case 'buttons':
            return (
              <ButtonControl
                key={`buttons-${index}`}
                items={control.items}
                onButtonClick={handleButtonClick}
                disabled={isOffline}
              />
            );

          default:
            return null;
        }
      })}
    </div>
  );
}

export default FeatureCard;
